using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedLabel { get; set; } = string.Empty;

    [ColumnName("Score")]
    public float[] Score { get; set; } = [];
}

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class TicketPredictionResponse
{
    public string Category { get; set; } = string.Empty;
    public float Confidence { get; set; }
    public Dictionary<string, float> Probabilities { get; set; } = new();
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainerService : IHostedService
{
    private readonly ILogger<ModelTrainerService> _logger;

    public ModelTrainerService(ILogger<ModelTrainerService> logger)
    {
        _logger = logger;
    }

    public Task StartAsync(CancellationToken cancellationToken)
    {
        var mlContext = new MLContext(seed: 42);

        var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        if (!File.Exists(dataPath))
        {
            dataPath = Path.Combine(Directory.GetCurrentDirectory(), "Data", "tickets.csv");
        }

        _logger.LogInformation("Loading training data from {DataPath}", dataPath);

        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath,
            hasHeader: true,
            separatorChar: ',',
            allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketInput.Category)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        _logger.LogInformation("=== Model Evaluation Metrics ===");
        _logger.LogInformation("MacroAccuracy:  {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("MicroAccuracy:  {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("LogLoss:        {LogLoss:F4}", metrics.LogLoss);

        _logger.LogInformation("=== Per-class Metrics ===");
        for (int i = 0; i < metrics.PerClassLogLoss.Count; i++)
        {
            _logger.LogInformation("  Class {Index}: LogLoss = {LogLoss:F4}", i, metrics.PerClassLogLoss[i]);
        }

        var modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "TicketModel.zip");
        if (!File.Exists(Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv")))
        {
            modelPath = Path.Combine(Directory.GetCurrentDirectory(), "Data", "TicketModel.zip");
        }

        mlContext.Model.Save(model, data.Schema, modelPath);
        _logger.LogInformation("Model saved to {ModelPath}", modelPath);

        return Task.CompletedTask;
    }

    public Task StopAsync(CancellationToken cancellationToken) => Task.CompletedTask;
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionEnginePool;

    public TicketClassifierController(PredictionEnginePool<TicketInput, TicketPrediction> predictionEnginePool)
    {
        _predictionEnginePool = predictionEnginePool;
    }

    [HttpPost("predict")]
    public ActionResult<TicketPredictionResponse> Predict([FromBody] TicketRequest request)
    {
        if (request.Priority < 1 || request.Priority > 3)
        {
            return BadRequest("Priority must be between 1 and 3.");
        }

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEnginePool.Predict(input);

        // Get label names from the model schema
        var labelNames = GetLabelNames();
        var probabilities = new Dictionary<string, float>();

        for (int i = 0; i < prediction.Score.Length && i < labelNames.Length; i++)
        {
            probabilities[labelNames[i]] = prediction.Score[i];
        }

        var confidence = prediction.Score.Length > 0 ? prediction.Score.Max() : 0f;

        return Ok(new TicketPredictionResponse
        {
            Category = prediction.PredictedLabel,
            Confidence = confidence,
            Probabilities = probabilities
        });
    }

    [HttpGet("categories")]
    public ActionResult<IEnumerable<string>> GetCategories()
    {
        return Ok(new[] { "Billing", "General", "Technical" });
    }

    private string[] GetLabelNames()
    {
        var modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "TicketModel.zip");
        if (!System.IO.File.Exists(modelPath))
        {
            modelPath = Path.Combine(Directory.GetCurrentDirectory(), "Data", "TicketModel.zip");
        }

        var mlContext = new MLContext();
        var model = mlContext.Model.Load(modelPath, out var schema);

        var outputSchema = model.GetOutputSchema(schema);
        var labelColumn = outputSchema.GetColumnOrNull("PredictedLabel");

        if (labelColumn == null)
            return ["Billing", "General", "Technical"];

        // Get key values from the Label column (before MapKeyToValue)
        var labelKeyColumn = outputSchema.GetColumnOrNull("Label");
        if (labelKeyColumn != null)
        {
            var keyType = labelKeyColumn.Value.Type as Microsoft.ML.Data.KeyDataViewType;
            if (keyType != null)
            {
                var slotNames = new Microsoft.ML.Data.VBuffer<ReadOnlyMemory<char>>();
                labelKeyColumn.Value.GetKeyValues(ref slotNames);
                return slotNames.DenseValues().Select(v => v.ToString()).ToArray();
            }
        }

        return ["Billing", "General", "Technical"];
    }
}

