1. using Microsoft.ML;
2. using TicketClassifier.Models;
3. 
4. namespace TicketClassifier.Services;
5. 
6. public class ModelTrainerService : IHostedService
7. {
8.     private readonly ILogger<ModelTrainerService> _logger;
9. 
10.     public ModelTrainerService(ILogger<ModelTrainerService> logger)
11.     {
12.         _logger = logger;
13.     }
14. 
15.     public Task StartAsync(CancellationToken cancellationToken)
16.     {
17.         var mlContext = new MLContext(seed: 42);
18. 
19.         var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
20.         if (!File.Exists(dataPath))
21.         {
22.             dataPath = Path.Combine(Directory.GetCurrentDirectory(), "Data", "tickets.csv");
23.         }
24. 
25.         _logger.LogInformation("Loading training data from {DataPath}", dataPath);
26. 
27.         var data = mlContext.Data.LoadFromTextFile<TicketInput>(
28.             dataPath,
29.             hasHeader: true,
30.             separatorChar: ',',
31.             allowQuoting: true);
32. 
33.         var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);
34. 
35.         var pipeline = mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject))
36.             .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
37.             .Append(mlContext.Transforms.Concatenate("Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
38.             .Append(mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketInput.Category)))
39.             .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
40.             .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));
41. 
42.         _logger.LogInformation("Training model...");
43.         var model = pipeline.Fit(split.TrainSet);
44. 
