 using Microsoft.AspNetCore.Mvc;
 using Microsoft.Extensions.ML;
 using Microsoft.ML;
 using Microsoft.ML.Data;
 using TicketClassifier.Models;

 namespace TicketClassifier.Controllers;

 [ApiController]
 [Route("api/[controller]")]
 public class TicketClassifierController : ControllerBase
 {
     private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionEnginePool;

     public TicketClassifierController(PredictionEnginePool<TicketInput, TicketPrediction> predictionEnginePool)
     {
         _predictionEnginePool = predictionEnginePool;
     }

     [HttpPost("predict")]
     public ActionResult<TicketPredictionResponse> Predict([FromBody] TicketRequest request)
     {
         if (request.Priority < 1 || request.Priority > 3)
         {
             return BadRequest("Priority must be between 1 and 3.");
         }

         var input = new TicketInput
         {
             Subject = request.Subject,
             Description = request.Description,
             Priority = request.Priority
         };

         var prediction = _predictionEnginePool.Predict(input);

         // Get label names from the model schema
         var labelNames = GetLabelNames();
         var probabilities = new Dictionary<string, float>();

         for (int i = 0; i < prediction.Score.Length && i < labelNames.Length; i++)
         {
             probabilities[labelNames[i]] = prediction.Score[i];
         }

         var confidence = prediction.Score.Length > 0 ? prediction.Score.Max() : 0f;

         return Ok(new TicketPredictionResponse
         {
             Category = prediction.PredictedLabel,
             Confidence = confidence,
             Probabilities = probabilities
         });
     }

     [HttpGet("categories")]
     public ActionResult<IEnumerable<string>> GetCategories()
     {
         return Ok(new[] { "Billing", "General", "Technical" });
     }

     private string[] GetLabelNames()
     {
         var modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "TicketModel.zip");
         if (!System.IO.File.Exists(modelPath))
         {
             modelPath = Path.Combine(Directory.GetCurrentDirectory(), "Data", "TicketModel.zip");
         }

         var mlContext = new MLContext();
         var model = mlContext.Model.Load(modelPath, out var schema);

         var outputSchema = model.GetOutputSchema(schema);
         var labelColumn = outputSchema.GetColumnOrNull("Label");

         if (labelColumn == null)
             return ["Billing", "General", "Technical"];

         var column = labelColumn.Value;
         if (column.HasKeyValues())
         {
             var slotNames = new Microsoft.ML.Data.VBuffer<ReadOnlyMemory<char>>();
             column.GetKeyValues(ref slotNames);
             return slotNames.DenseValues().Select(v => v.ToString()).ToArray();
         }

         return ["Billing", "General", "Technical"];
     }
 }

